// ── JSONB shape types (for casting at point of use) ───────────────
// These columns are stored as `jsonb` in the DB and generated as `Json`.
// Use these types when you need to access specific fields after reading.

export type AddressJson = {
  name: string;
  street: string;
  city: string;
  zip: string;
  country: string;
};

export type BillingAddressJson = AddressJson & {
  company_name?: string;
  tax_number?: string;
};

export type PickupPointJson = {
  provider?: string;
  point_id?: string;
  point_label?: string;
};

export type VariantSnapshotJson = {
  option1Name?: string;
  option1Value?: string;
  option2Name?: string;
  option2Value?: string;
  sku?: string;
};

/** Shape of the features JSONB column in shop_plans / feature_overrides in shop_subscriptions */
export type PlanFeaturesJson = {
  max_products: number;
  max_admins: number;
  max_categories: number;
  delivery_options: number;
  enable_coupons: boolean;
  enable_marketing_module: boolean;
  enable_abandoned_cart: boolean;
  enable_b2b_wholesale: boolean;
  enable_reviews: boolean;
  enable_price_history: boolean;
  enable_product_extras: boolean;
  enable_scheduled_publishing: boolean;
  enable_agency_viewer: boolean;
  enable_custom_pages: boolean;
  enable_blog: boolean;
};

// ── Structured content types for CMS pages (FE-023) ───────────────

export type AboutUsHeroSection = {
  title: string;
  subtitle: string;
  imageUrl: string | null;
};

export type AboutUsStorySection = {
  title: string;
  body: string;
};

export type AboutUsTeamMember = {
  name: string;
  role: string;
  imageUrl: string | null;
  bio: string;
};

export type AboutUsValue = {
  title: string;
  description: string;
  icon: string;
};

export type AboutUsContactSection = {
  address: string;
  phone: string;
  email: string;
  mapEmbedUrl: string | null;
};

export type AboutUsContent = {
  hero: AboutUsHeroSection;
  story: AboutUsStorySection;
  team: AboutUsTeamMember[];
  values: AboutUsValue[];
  contact: AboutUsContactSection;
};

// ── Enriched / join types (not in DB, assembled in server actions) ─

/** OrderNote with resolved author name for display */
export type OrderNoteWithAuthor = OrderNoteRow & {
  author_name: string | null;
};

/** Extra row enriched with the extra product's live price and stock info */
export type ProductExtraWithProduct = ProductExtraRow & {
  extra_product_title: string;
  extra_product_slug: string;
  extra_product_price: number;
  extra_product_image: string | null;
  extra_product_is_active: boolean;
  extra_variant_price: number | null;
  extra_variant_stock: number | null;
  extra_variant_is_active: boolean | null;
};

/** Subscription enriched with its associated plan for display */
export type ShopSubscriptionWithPlan = ShopSubscriptionRow & {
  plan: ShopPlanRow;
};

/** Review enriched with author name for storefront display */
export type ReviewWithUser = ReviewRow & {
  author_name: string | null;
};

/** Review enriched with product info for admin moderation list */
export type ReviewWithProduct = ReviewRow & {
  product_title: string;
  product_slug: string;
  product_main_image_url: string | null;
  author_name: string | null;
};

/** Aggregated review statistics for a product (from product_review_stats view) */
export type ReviewStats = {
  product_id: string;
  review_count: number;
  average_rating: number;
  five_star: number;
  four_star: number;
  three_star: number;
  two_star: number;
  one_star: number;
};

/** Post summary for public blog list */
export type PostSummary = Pick<
  PostRow,
  "id" | "slug" | "title" | "excerpt" | "cover_image_url" | "published_at" | "tags"
> & {
  author_name: string | null;
};

/** Full post detail for public single post page */
export type PostDetail = PostRow & {
  author_name: string | null;
};

/** Post row enriched for admin list */
export type PostAdmin = PostRow & {
  author_name: string | null;
};
